'use client'
import { useState } from 'react'
import { useParams } from 'next/navigation'
import Link from 'next/link'
import Card from '../../../../../components/ui/Card'
import Badge from '../../../../../components/ui/Badge'
import Button from '../../../../../components/ui/Button'
import Modal from '../../../../../components/ui/Modal'
import {
  ArrowLeft,
  User,
  FileText,
  CheckCircle,
  XCircle,
  Link as LinkIcon,
  Download,
} from 'lucide-react'
import { formatDate, formatTxHash } from '../../../../../lib/utils'
import { DOCUMENT_TYPES } from '../../../../../lib/constants'

// Sample data — will come from API later
const application = {
  id:             1,
  veteran_name:   'Subedar Ram Kumar',
  service_no:     '15701234P',
  rank:           'Subedar',
  regiment:       '3rd Battalion, Rajput Regiment',
  email:          'ram.kumar@example.com',
  phone:          '+91 98765 43210',
  scheme:         'Disability Pension',
  category:       'pension',
  status:         'under_review' as const,
  submitted_at:   '2026-03-08T10:00:00Z',
  reason:         'I was injured during active duty in 2023. The medical board has certified 40% disability. I am applying for disability pension as per the entitlement rules.',
  remarks:        '',
  sla_days_left:  19,
  blockchain_tx_hash: '0x4a3b2c1d9e8f7a6b5c4d3e2f1a0b9c8d',
  documents: [
    {
      id:           1,
      doc_type:     'discharge_certificate',
      file_name:    'discharge_cert.pdf',
      ipfs_hash:    'QmXoypizjW3WknFiJnKLwHCnL72vedxjQkDDP1mXWo6uco',
      is_verified:  true,
    },
    {
      id:           2,
      doc_type:     'medical_certificate',
      file_name:    'medical_board_report.pdf',
      ipfs_hash:    'QmYwAPJzv5CZsnA625s3Xf2nemtYgPpHdWEz79ojWnPbdG',
      is_verified:  true,
    },
    {
      id:           3,
      doc_type:     'service_record',
      file_name:    'service_record.pdf',
      ipfs_hash:    'QmZ9iq2mf2Yy3S1AqX7vANgRXiZi5M9PWrkH3MdNWaJM3',
      is_verified:  false,
    },
  ],
}

export default function ApplicationReviewPage() {
  const { id }          = useParams()
  const [approveModal,  setApproveModal]  = useState(false)
  const [rejectModal,   setRejectModal]   = useState(false)
  const [remarks,       setRemarks]       = useState('')
  const [loading,       setLoading]       = useState(false)
  const [actionDone,    setActionDone]    = useState<'approved' | 'rejected' | null>(null)

  async function handleApprove() {
    setLoading(true)
    await new Promise((res) => setTimeout(res, 1500))
    setLoading(false)
    setApproveModal(false)
    setActionDone('approved')
  }

  async function handleReject() {
    if (!remarks.trim()) return
    setLoading(true)
    await new Promise((res) => setTimeout(res, 1500))
    setLoading(false)
    setRejectModal(false)
    setActionDone('rejected')
  }

  if (actionDone) {
    return (
      <div className="max-w-lg mx-auto text-center py-16">
        <div className={`w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6 ${
          actionDone === 'approved' ? 'bg-green-100' : 'bg-red-100'
        }`}>
          {actionDone === 'approved'
            ? <CheckCircle size={40} className="text-green-700" />
            : <XCircle    size={40} className="text-red-600"   />
          }
        </div>
        <h2 className="text-2xl font-bold text-gray-900 mb-2">
          Application {actionDone === 'approved' ? 'Approved' : 'Rejected'}
        </h2>
        <p className="text-gray-500 mb-6">
          The decision has been recorded and anchored on the blockchain.
          The veteran will be notified via email and Telegram.
        </p>
        <Link href="/officer/applications">
          <Button variant="primary" size="lg">Back to Applications</Button>
        </Link>
      </div>
    )
  }

  return (
    <div className="space-y-6 max-w-3xl">

      {/* Back */}
      <Link
        href="/officer/applications"
        className="inline-flex items-center gap-2 text-sm text-gray-500 hover:text-gray-700"
      >
        <ArrowLeft size={16} /> Back to Applications
      </Link>

      {/* Header */}
      <div className="flex items-start justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">
            Application #{id}
          </h1>
          <p className="text-gray-500 text-sm mt-1">{application.scheme}</p>
        </div>
        <div className="flex items-center gap-2">
          <div className="text-xs font-semibold px-3 py-1.5 rounded-full bg-yellow-100 text-yellow-700">
            {application.sla_days_left} days left
          </div>
          <Badge label="Under Review" color="yellow" />
        </div>
      </div>

      {/* Veteran info */}
      <Card padding="md">
        <h3 className="text-sm font-semibold text-gray-700 mb-4 flex items-center gap-2">
          <User size={16} className="text-blue-700" /> Veteran Details
        </h3>
        <div className="grid grid-cols-2 gap-3 text-sm">
          <div>
            <p className="text-gray-400 text-xs">Full Name</p>
            <p className="font-semibold text-gray-800">{application.veteran_name}</p>
          </div>
          <div>
            <p className="text-gray-400 text-xs">Service Number</p>
            <p className="font-semibold text-gray-800">{application.service_no}</p>
          </div>
          <div>
            <p className="text-gray-400 text-xs">Rank</p>
            <p className="font-semibold text-gray-800">{application.rank}</p>
          </div>
          <div>
            <p className="text-gray-400 text-xs">Regiment</p>
            <p className="font-semibold text-gray-800">{application.regiment}</p>
          </div>
          <div>
            <p className="text-gray-400 text-xs">Email</p>
            <p className="font-semibold text-gray-800">{application.email}</p>
          </div>
          <div>
            <p className="text-gray-400 text-xs">Phone</p>
            <p className="font-semibold text-gray-800">{application.phone}</p>
          </div>
          <div>
            <p className="text-gray-400 text-xs">Submitted On</p>
            <p className="font-semibold text-gray-800">
              {formatDate(application.submitted_at)}
            </p>
          </div>
        </div>
      </Card>

      {/* Application reason */}
      <Card padding="md">
        <h3 className="text-sm font-semibold text-gray-700 mb-3 flex items-center gap-2">
          <FileText size={16} className="text-blue-700" /> Reason for Application
        </h3>
        <p className="text-sm text-gray-700 bg-gray-50 rounded-lg p-4 leading-relaxed">
          {application.reason}
        </p>
      </Card>

      {/* Documents */}
      <Card padding="md">
        <h3 className="text-sm font-semibold text-gray-700 mb-4 flex items-center gap-2">
          <FileText size={16} className="text-blue-700" /> Submitted Documents
        </h3>
        <div className="space-y-3">
          {application.documents.map((doc) => (
            <div
              key={doc.id}
              className="flex items-center justify-between p-3 bg-gray-50 rounded-xl"
            >
              <div className="flex items-center gap-3">
                <div className="w-8 h-8 bg-blue-100 rounded-lg flex items-center justify-center">
                  <FileText size={14} className="text-blue-700" />
                </div>
                <div>
                  <p className="text-sm font-medium text-gray-800">
                    {DOCUMENT_TYPES[doc.doc_type as keyof typeof DOCUMENT_TYPES]}
                  </p>
                  <p className="text-xs text-gray-400">{doc.file_name}</p>
                </div>
              </div>
              <div className="flex items-center gap-2">
                {doc.is_verified ? (
                  <Badge label="Verified" color="green" size="sm" />
                ) : (
                  <Badge label="Unverified" color="yellow" size="sm" />
                )}
                
                <a  href={`http://localhost:8080/ipfs/${doc.ipfs_hash}`}
                  target="_blank"
                  rel="noreferrer"
                  className="p-1.5 rounded-lg hover:bg-gray-200 transition-colors"
                >
                  <Download size={14} className="text-gray-500" />
                </a>
              </div>
            </div>
          ))}
        </div>
      </Card>

      {/* Blockchain info */}
      {application.blockchain_tx_hash && (
        <Card padding="md" className="border-green-100 bg-green-50">
          <div className="flex items-center gap-3">
            <LinkIcon size={18} className="text-green-700 shrink-0" />
            <div>
              <p className="text-sm font-semibold text-green-800">
                Blockchain Anchored
              </p>
              <code className="text-xs text-green-600">
                {formatTxHash(application.blockchain_tx_hash)}
              </code>
            </div>
          </div>
        </Card>
      )}

      {/* Action buttons */}
      <div className="flex gap-3">
        <Button
          variant="primary"
          size="lg"
          className="flex-1"
          onClick={() => setApproveModal(true)}
        >
          <CheckCircle size={18} className="mr-2" /> Approve Application
        </Button>
        <Button
          variant="danger"
          size="lg"
          className="flex-1"
          onClick={() => setRejectModal(true)}
        >
          <XCircle size={18} className="mr-2" /> Reject Application
        </Button>
      </div>

      {/* Approve Modal */}
      <Modal
        isOpen={approveModal}
        onClose={() => setApproveModal(false)}
        title="Confirm Approval"
        size="sm"
      >
        <div className="space-y-4">
          <p className="text-sm text-gray-600">
            Are you sure you want to approve this application for{' '}
            <strong>{application.veteran_name}</strong>?
            This decision will be recorded on the blockchain.
          </p>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1.5">
              Remarks (optional)
            </label>
            <textarea
              rows={3}
              value={remarks}
              onChange={(e) => setRemarks(e.target.value)}
              placeholder="Add any remarks for the veteran..."
              className="w-full px-4 py-2.5 rounded-lg border border-gray-300 text-sm focus:outline-none focus:ring-2 focus:ring-green-500 resize-none"
            />
          </div>
          <div className="flex gap-3">
            <Button
              variant="ghost"
              className="flex-1"
              onClick={() => setApproveModal(false)}
            >
              Cancel
            </Button>
            <Button
              variant="primary"
              className="flex-1"
              loading={loading}
              onClick={handleApprove}
            >
              Confirm Approve
            </Button>
          </div>
        </div>
      </Modal>

      {/* Reject Modal */}
      <Modal
        isOpen={rejectModal}
        onClose={() => setRejectModal(false)}
        title="Confirm Rejection"
        size="sm"
      >
        <div className="space-y-4">
          <p className="text-sm text-gray-600">
            Please provide a reason for rejecting this application.
            The veteran will be notified with this reason.
          </p>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1.5">
              Rejection Reason <span className="text-red-500">*</span>
            </label>
            <textarea
              rows={4}
              value={remarks}
              onChange={(e) => setRemarks(e.target.value)}
              placeholder="Explain why this application is being rejected..."
              className="w-full px-4 py-2.5 rounded-lg border border-gray-300 text-sm focus:outline-none focus:ring-2 focus:ring-red-500 resize-none"
            />
          </div>
          <div className="flex gap-3">
            <Button
              variant="ghost"
              className="flex-1"
              onClick={() => setRejectModal(false)}
            >
              Cancel
            </Button>
            <Button
              variant="danger"
              className="flex-1"
              loading={loading}
              disabled={!remarks.trim()}
              onClick={handleReject}
            >
              Confirm Reject
            </Button>
          </div>
        </div>
      </Modal>

    </div>
  )
}
